"""Load the flag manifest (generated by scripts/gen_manifest.py)."""
from __future__ import annotations

import json
from functools import lru_cache
from typing import Any

from .config import settings


@lru_cache(maxsize=1)
def load_manifest() -> dict[str, dict[str, Any]]:
    """benchmark name -> manifest entry."""
    data = json.loads(settings.flag_manifest.read_text())
    return {e["benchmark"]: e for e in data}


def manifest_entries() -> list[dict[str, Any]]:
    return list(load_manifest().values())


def get(benchmark: str) -> dict[str, Any] | None:
    return load_manifest().get(benchmark)
